INSERT INTO public.play_questions (domain, category, difficulty_rating, content, options, correct_answer_index, explanation)
VALUES
  ('academic', 'math', 1380, $m001c${"text":"Why does \\(\\lim_{x \\to n}[x]\\) not exist when \\(n\\) is an integer? ([ ] = greatest integer function.)","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"limits_continuity"}$m001c$::jsonb, $m001o$["LHL \\(\\to n-1\\) and RHL \\(\\to n\\); one-sided limits disagree.","The function is undefined at every integer.","The limit always equals \\(n\\).","\\([x]\\) is continuous at integers."]$m001o$::jsonb, 0, $m001e$Floor/step jumps: left limit and right limit at \(n\) differ.$m001e$),
  ('academic', 'math', 1386, $m002c${"text":"\\(\\displaystyle\\lim_{x \\to 0} \\frac{\\sin x - x}{x^3}\\)","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"limits_continuity"}$m002c$::jsonb, $m002o$["\\(-1/6\\)","\\(1/6\\)","\\(0\\)","\\(-1/2\\)"]$m002o$::jsonb, 0, $m002e$\(\sin x = x - x^3/6 + \cdots\) ⇒ numerator \(\sim -x^3/6\).$m002e$),
  ('academic', 'math', 1392, $m003c${"text":"Can a **jump** discontinuity be removed by redefining \\(f\\) at a single point?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"limits_continuity"}$m003c$::jsonb, $m003o$["No — LHL \\(\\neq\\) RHL, so no single value makes the limit exist.","Yes — always, like a removable discontinuity.","Only if the jump is rational.","Only for piecewise linear functions."]$m003o$::jsonb, 0, $m003e$Removable needs LHL = RHL \(\neq f(c)\); jump has unequal one-sided limits.$m003e$),
  ('academic', 'math', 1398, $m004c${"text":"Fundamental period of \\(f(x) = \\sin^4 x + \\cos^4 x\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"limits_continuity"}$m004c$::jsonb, $m004o$["\\(\\pi/2\\)","\\(\\pi\\)","\\(2\\pi\\)","\\(\\pi/4\\)"]$m004o$::jsonb, 0, $m004e$Reduce to \(1 - \tfrac12\sin^2 2x\); \(\sin^2 2x\) has period \(\pi/2\).$m004e$),
  ('academic', 'math', 1404, $m005c${"text":"Can a function be continuous on a closed bounded interval \\([a,b]\\) but **not** uniformly continuous on \\((a,b)\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"limits_continuity"}$m005c$::jsonb, $m005o$["On **[a,b]** closed and bounded: **no** — Heine–Cantor: continuous on a compact set is uniformly continuous.","Yes — always on every closed interval.","Only if it is unbounded.","Uniform continuity never holds in calculus."]$m005o$::jsonb, 0, $m005e$Compact interval \([a,b]\) + continuity \(\Rightarrow\) uniform continuity.$m005e$),
  ('academic', 'math', 1411, $m006c${"text":"\\(\\displaystyle\\lim_{n \\to \\infty} \\sum_{r=1}^{n} \\frac{n}{n^2 + r^2}\\)","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"limits_continuity"}$m006c$::jsonb, $m006o$["\\(\\pi/4\\)","\\(1/2\\)","\\(0\\)","\\(1\\)"]$m006o$::jsonb, 0, $m006e$Riemann sum \(\int_0^1 \frac{1}{1+x^2}\,dx = \tan^{-1}1\).$m006e$),
  ('academic', 'math', 1417, $m007c${"text":"Why is the Dirichlet function (1 on rationals, 0 on irrationals) nowhere continuous on \\(\\mathbb{R}\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"limits_continuity"}$m007c$::jsonb, $m007o$["Both rationals and irrationals are dense; every neighborhood hits both 0 and 1.","It is continuous only at \\(x=0\\).","It equals zero almost everywhere.","Limits exist everywhere."]$m007o$::jsonb, 0, $m007e$\(\varepsilon\)-\(\delta\) fails: no local constancy.$m007e$),
  ('academic', 'math', 1423, $m008c${"text":"How many **real** solutions does \\(e^x = x^2\\) have?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"limits_continuity"}$m008c$::jsonb, $m008o$["**3** (one negative, two positive — standard graphical/IVT count)","\\(1\\) only","\\(2\\) only","\\(0\\)"]$m008o$::jsonb, 0, $m008e$Sketch \(e^x\) vs \(x^2\); sign changes locate three crossings (well-known classic).$m008e$),
  ('academic', 'math', 1429, $m009c${"text":"How is Rolle’s theorem a special case of Lagrange’s MVT?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"limits_continuity"}$m009c$::jsonb, $m009o$["MVT: \\(f'(c) = \\frac{f(b)-f(a)}{b-a}\\). Rolle adds \\(f(a)=f(b)\\) so the secant slope is 0 ⇒ \\(f'(c)=0\\).","Rolle is stronger and never uses derivatives.","They apply to disjoint intervals only.","MVT is only for linear functions."]$m009o$::jsonb, 0, $m009e$Net change of \(f\) over \([a,b]\) is zero.$m009e$),
  ('academic', 'math', 1435, $m010c${"text":"Let \\(f(x) = x^3 + x\\). Find \\((f^{-1})'(2)\\).","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"limits_continuity"}$m010c$::jsonb, $m010o$["\\(1/4\\)","\\(4\\)","\\(1/2\\)","\\(1\\)"]$m010o$::jsonb, 0, $m010e$\(f(1)=2\); \((f^{-1})'(y) = 1/f'(x)\); \(f'(1)=4\).$m010e$),
  ('academic', 'math', 1442, $m011c${"text":"Why is \\(f(x) = |x-a|\\) usually **not** differentiable at \\(x=a\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"derivatives_apps"}$m011c$::jsonb, $m011o$["Left derivative \\(-1\\), right derivative \\(+1\\); corner — no unique tangent.","The function is undefined at \\(a\\).","Absolute value is never differentiable anywhere.","Only because \\(a\\) is irrational."]$m011o$::jsonb, 0, $m011e$One-sided derivatives differ at the kink.$m011e$),
  ('academic', 'math', 1448, $m012c${"text":"Maximum volume of a right circular cylinder inscribed in a sphere of radius \\(R\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"derivatives_apps"}$m012c$::jsonb, $m012o$["\\(4\\pi R^3/(3\\sqrt{3})\\)","\\(4\\pi R^3/3\\)","\\(\\pi R^3/\\sqrt{2}\\)","\\(2\\pi R^3/3\\)"]$m012o$::jsonb, 0, $m012e$Optimize \(V(h)\) with constraint \(r^2 + (h/2)^2 = R^2\).$m012e$),
  ('academic', 'math', 1454, $m013c${"text":"Why is \\(f'(c)=0\\) **necessary** but **not sufficient** for a local extremum?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"derivatives_apps"}$m013c$::jsonb, $m013o$["Saddle/inflection: e.g. \\(f(x)=x^3\\) at \\(0\\) has \\(f'(0)=0\\) but no max/min.","It is always sufficient for a maximum.","Derivatives do not exist at extrema.","Only for discontinuous functions."]$m013o$::jsonb, 0, $m013e$First derivative test can fail without sign change of \(f'\).$m013e$),
  ('academic', 'math', 1460, $m014c${"text":"Shortest distance between line \\(y=x\\) and parabola \\(y^2 = x-2\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"derivatives_apps"}$m014c$::jsonb, $m014o$["\\(7/(4\\sqrt{2})\\)","\\(7/4\\)","\\(\\sqrt{2}\\)","\\(1/\\sqrt{2}\\)"]$m014o$::jsonb, 0, $m014e$Parallel tangent to \(y=x\); point \((9/4,\,1/2)\); distance to \(x-y=0\).$m014e$),
  ('academic', 'math', 1466, $m015c${"text":"Geometric meaning of Lagrange’s MVT on \\([a,b]\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"derivatives_apps"}$m015c$::jsonb, $m015o$["Some \\(c\\in(a,b)\\) where tangent slope equals secant slope \\((f(b)-f(a))/(b-a)\\).","Tangent is always horizontal.","Secant does not exist.","Only for polynomials of degree 2."]$m015o$::jsonb, 0, $m015e$Instantaneous rate matches average rate.$m015e$),
  ('academic', 'math', 1473, $m016c${"text":"If \\(x^y = e^{x-y}\\), find \\(\\displaystyle\\left.\\frac{dy}{dx}\\right|_{x=e}\\).","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"derivatives_apps"}$m016c$::jsonb, $m016o$["\\(1/4\\)","\\(1/2\\)","\\(0\\)","\\(1\\)"]$m016o$::jsonb, 0, $m016e$\(\ln\): \(y\ln x = x-y\) ⇒ \(y = x/(1+\ln x)\); quotient rule at \(x=e\).$m016e$),
  ('academic', 'math', 1479, $m017c${"text":"What **defines** an inflection point (vs a mere stationary point)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"derivatives_apps"}$m017c$::jsonb, $m017o$["Concavity changes — typically \\(f''\\) changes sign (under mild assumptions).","Only where \\(f'=0\\).","Only where \\(f''=0\\) always, with no sign change needed.","A point where the function is undefined."]$m017o$::jsonb, 0, $m017e$Curvature switches from cup-up to cup-down or vice versa.$m017e$),
  ('academic', 'math', 1485, $m018c${"text":"Spherical balloon: \\(dV/dt = 10\\ \\mathrm{cm^3/s}\\). Find \\(dA/dt\\) when \\(r = 5\\ \\mathrm{cm}\\).","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"derivatives_apps"}$m018c$::jsonb, $m018o$["\\(4\\ \\mathrm{cm^2/s}\\)","\\(2\\ \\mathrm{cm^2/s}\\)","\\(8\\ \\mathrm{cm^2/s}\\)","\\(10\\ \\mathrm{cm^2/s}\\)"]$m018o$::jsonb, 0, $m018e$\(V=\frac{4}{3}\pi r^3\), \(A=4\pi r^2\); chain rule.$m018e$),
  ('academic', 'math', 1491, $m019c${"text":"When does a cubic \\(f\\) have **no** local extrema on \\(\\mathbb{R}\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"derivatives_apps"}$m019c$::jsonb, $m019o$["When \\(f'(x)\\) (a quadratic) has no two distinct real roots — discriminant \\(\\le 0\\) ⇒ \\(f'\\) doesn’t change sign.","When the leading coefficient is zero.","Always — cubics have no extrema.","When \\(f''>0\\) everywhere."]$m019o$::jsonb, 0, $m019e$Monotone cubic ⇔ derivative quadratic has \(\le 1\) real root.$m019e$),
  ('academic', 'math', 1497, $m020c${"text":"Absolute maximum of \\(f(x) = x^{1/x}\\) for \\(x>0\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"derivatives_apps"}$m020c$::jsonb, $m020o$["\\(e^{1/e}\\)","\\(e\\)","\\(1\\)","\\(e^{-1}\\)"]$m020o$::jsonb, 0, $m020e$Log-derivative; maximum at \(x=e\).$m020e$),
  ('academic', 'math', 1504, $m021c${"text":"Why does \\(+C\\) appear in indefinite integrals but not in definite \\(\\int_a^b\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"integration"}$m021c$::jsonb, $m021o$["Constants cancel: \\(F(b)+C - (F(a)+C) = F(b)-F(a)\\).","Definite integral always equals zero.","Fundamental theorem forbids constants.","Only polynomials need \\(C\\)."]$m021o$::jsonb, 0, $m021e$FTC: antiderivative evaluated at endpoints.$m021e$),
  ('academic', 'math', 1510, $m022c${"text":"\\(\\displaystyle\\int_0^{\\pi/2} \\frac{\\sqrt{\\sin x}}{\\sqrt{\\sin x}+\\sqrt{\\cos x}}\\,dx\\)","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"integration"}$m022c$::jsonb, $m022o$["\\(\\pi/4\\)","\\(\\pi/2\\)","\\(0\\)","\\(1\\)"]$m022o$::jsonb, 0, $m022e$Use \(\int_0^{\pi/2} f(x)\,dx = \int_0^{\pi/2} f(\pi/2-x)\,dx\); add.$m022e$),
  ('academic', 'math', 1516, $m023c${"text":"What does the **Leibniz rule** let you differentiate?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"integration"}$m023c$::jsonb, $m023o$["An integral \\(\\int_{u(t)}^{v(t)} g(x,t)\\,dx\\) w.r.t. \\(t\\) — limits (and integrand) may depend on \\(t\\).","Only polynomials.","Only improper integrals of first kind.","The constant \\(C\\) in indefinite integrals."]$m023o$::jsonb, 0, $m023e$Differentiation under the integral sign / variable limits.$m023e$),
  ('academic', 'math', 1522, $m024c${"text":"\\(\\displaystyle\\int e^x\\left(\\frac{1-x}{1+x^2}\\right)^2 dx\\)","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"integration"}$m024c$::jsonb, $m024o$["\\(e^x/(1+x^2) + C\\)","\\(e^x(1-x^2)/(1+x^2) + C\\)","\\(\\tan^{-1}x + C\\)","\\(e^x/(1-x)^2 + C\\)"]$m024o$::jsonb, 0, $m024e$Recognize \(e^x(f+f')\) form after algebra.$m024e$),
  ('academic', 'math', 1528, $m025c${"text":"How does **odd/even** symmetry simplify \\(\\int_{-a}^{a} f(x)\\,dx\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"integration"}$m025c$::jsonb, $m025o$["Odd ⇒ integral \\(0\\); even ⇒ \\(2\\int_0^a f\\).","Odd ⇒ double the integral; even ⇒ zero.","No simplification is possible.","Only for periodic functions."]$m025o$::jsonb, 0, $m025e$Symmetric interval + parity.$m025e$),
  ('academic', 'math', 1535, $m026c${"text":"\\(\\displaystyle\\int_0^{\\pi} x\\log(\\sin x)\\,dx\\)","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"integration"}$m026c$::jsonb, $m026o$["\\(-\\dfrac{\\pi^2}{2}\\log 2\\)","\\(0\\)","\\(\\pi\\log 2\\)","\\(-\\pi\\log 2\\)"]$m026o$::jsonb, 0, $m026e$Use \(x\to \pi-x\); relate to \(\int_0^\pi \log(\sin x)\,dx = -\pi\log 2\).$m026e$),
  ('academic', 'math', 1541, $m027c${"text":"ILATE in \\(\\int u\\,dv\\) is a rule of thumb because…","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"integration"}$m027c$::jsonb, $m027o$["Pick \\(u\\) so that \\(du\\) simplifies and \\(dv\\) is easy to integrate (log/inverse often for \\(u\\)).","It is a theorem proved for all integrands.","Trig must always be \\(dv\\).","Exponentials must always be \\(u\\)."]$m027o$::jsonb, 0, $m027e$Balance differentiation vs integration difficulty.$m027e$),
  ('academic', 'math', 1547, $m028c${"text":"\\(\\displaystyle\\int_0^{100\\pi} |\\sin x|\\,dx\\)","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"integration"}$m028c$::jsonb, $m028o$["\\(200\\)","\\(100\\)","\\(400\\)","\\(0\\)"]$m028o$::jsonb, 0, $m028e$\(|\sin x|\) has period \(\pi\); \(\int_0^\pi |\sin x|\,dx = 2\).$m028e$),
  ('academic', 'math', 1553, $m029c${"text":"Improper integral **of the first kind**?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"integration"}$m029c$::jsonb, $m029o$["Infinite limit(s) of integration (e.g. \\(\\int_1^\\infty\\)).","Integrand blows up inside \\([a,b]\\).","Only when integral equals \\(\\pi\\).","Same as Cauchy principal value always."]$m029o$::jsonb, 0, $m029e$Type 1: infinite interval; type 2: unbounded integrand on finite interval.$m029e$),
  ('academic', 'math', 1559, $m030c${"text":"\\(\\displaystyle\\int_{-\\infty}^{\\infty} e^{-x^2}\\,dx\\)","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"integration"}$m030c$::jsonb, $m030o$["\\(\\sqrt{\\pi}\\)","\\(\\pi\\)","\\(1\\)","\\(2\\sqrt{\\pi}\\)"]$m030o$::jsonb, 0, $m030e$Polar/double-integral trick; Gaussian.$m030e$),
  ('academic', 'math', 1566, $m031c${"text":"**Order** vs **degree** of a differential equation?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"diff_eq_area"}$m031c$::jsonb, $m031o$["Order = highest derivative present; degree = power of that highest derivative when DE is polynomial in derivatives.","They always mean the same thing.","Degree is always 1 for ODEs.","Order is the number of arbitrary constants."]$m031o$::jsonb, 0, $m031e$e.g. \((y'')^3 + y' = 0\): order 2, degree 3.$m031e$),
  ('academic', 'math', 1572, $m032c${"text":"Solve \\(\\dfrac{dy}{dx} = \\dfrac{x+y}{x}\\) (homogeneous).","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"diff_eq_area"}$m032c$::jsonb, $m032o$["\\(y = x\\log|x| + cx\\)","\\(y = x^2 + c\\)","\\(y = \\log x + c\\)","\\(y = ce^x\\)"]$m032o$::jsonb, 0, $m032e$Substitute \(y = vx\); cancel \(v\); integrate \(dv = dx/x\).$m032e$),
  ('academic', 'math', 1578, $m033c${"text":"When is an **integrating factor** \\(e^{\\int P\\,dx}\\) used for first-order linear ODEs?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"diff_eq_area"}$m033c$::jsonb, $m033o$["For \\(y' + P(x)y = Q(x)\\) to turn LHS into \\(\\frac{d}{dx}(y\\cdot \\mathrm{IF})\\).","Only when the equation is separable already.","Only for second-order equations.","Never — it is only for exact equations in \\(y\\)."]$m033o$::jsonb, 0, $m033e$Linear first-order standard form.$m033e$),
  ('academic', 'math', 1584, $m034c${"text":"Area enclosed by \\(y^2 = 4x\\) and \\(x^2 = 4y\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"diff_eq_area"}$m034c$::jsonb, $m034o$["\\(16/3\\)","\\(8/3\\)","\\(32/3\\)","\\(4\\)"]$m034o$::jsonb, 0, $m034e$Intersect at \((0,0)\) and \((4,4)\); \(\int_0^4 (2\sqrt{x} - x^2/4)\,dx\).$m034e$),
  ('academic', 'math', 1590, $m035c${"text":"What is an **orthogonal trajectory** of a family of curves?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"diff_eq_area"}$m035c$::jsonb, $m035o$["A curve meeting each member of the family at a right angle; DE from \\(-1/(dy/dx)\\) of given family.","A curve parallel to every member.","The envelope only.","A singular solution always."]$m035o$::jsonb, 0, $m035e$Slope negative reciprocal at intersections.$m035e$),
  ('academic', 'math', 1597, $m036c${"text":"Exponential growth: population doubles in 50 years. Growth constant \\(k\\) in \\(P = P_0 e^{kt}\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"diff_eq_area"}$m036c$::jsonb, $m036o$["\\((\\ln 2)/50\\)","\\(50/\\ln 2\\)","\\(\\ln 2\\)","\\(1/50\\)"]$m036o$::jsonb, 0, $m036e$\(2 = e^{50k}\Rightarrow k = \ln 2/50\).$m036e$),
  ('academic', 'math', 1603, $m037c${"text":"Why do **singular solutions** of an ODE often carry **no** arbitrary constant?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"diff_eq_area"}$m037c$::jsonb, $m037o$["They are envelopes / limits not reachable by fixing \\(C\\) in the general solution.","They always equal zero.","They are particular solutions with \\(C=0\\) only.","Arbitrary constants are illegal in ODEs."]$m037o$::jsonb, 0, $m037e$Lie outside the one-parameter family.$m037e$),
  ('academic', 'math', 1609, $m038c${"text":"Area between \\(y = \\sin x\\) and \\(y = \\cos x\\) from \\(0\\) to \\(\\pi/4\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"diff_eq_area"}$m038c$::jsonb, $m038o$["\\(\\sqrt{2} - 1\\)","\\(1 - \\sqrt{2}\\)","\\(0\\)","\\(\\sqrt{2}\\)"]$m038o$::jsonb, 0, $m038e$On \([0,\pi/4]\), \(\cos x \ge \sin x\); integrate difference.$m038e$),
  ('academic', 'math', 1615, $m039c${"text":"DE \\(y\\,dx - x\\,dy = 0\\) represents which family?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"diff_eq_area"}$m039c$::jsonb, $m039o$["Straight lines through the origin \\(y = kx\\).","Circles centered at origin.","Hyperbolas only.","Parabolas only."]$m039o$::jsonb, 0, $m039e$\(dy/dx = y/x\) ⇒ separable ⇒ \(\ln|y| = \ln|x|+C\).$m039e$),
  ('academic', 'math', 1621, $m040c${"text":"Solve \\(y'' + 4y = 0\\), \\(y(0)=1\\), \\(y'(0)=0\\).","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"diff_eq_area"}$m040c$::jsonb, $m040o$["\\(y = \\cos(2x)\\)","\\(y = \\sin(2x)\\)","\\(y = \\cos x\\)","\\(y = e^{-2x}\\)"]$m040o$::jsonb, 0, $m040e$\(r^2+4=0\Rightarrow r=\pm 2i\); ICs give \(A=1,B=0\).$m040e$),
  ('academic', 'math', 1628, $m041c${"text":"Role of **De Moivre** \\((\\cos\\theta+i\\sin\\theta)^n = \\cos n\\theta + i\\sin n\\theta\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"complex_quad"}$m041c$::jsonb, $m041o$["Turns powers of complex numbers on the unit circle into angle multiplication.","Only expands binomials with real roots.","Computes matrix rank.","Only for \\(n<0\\)."]$m041o$::jsonb, 0, $m041e$Bridges complex exponentials/trig for integer \(n\).$m041e$),
  ('academic', 'math', 1634, $m042c${"text":"\\(\\omega\\) a non-real cube root of unity. \\((1-\\omega+\\omega^2)^5 + (1+\\omega-\\omega^2)^5\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"complex_quad"}$m042c$::jsonb, $m042o$["\\(32\\)","\\(0\\)","\\(-32\\)","\\(64\\)"]$m042o$::jsonb, 0, $m042e$Use \(1+\omega+\omega^2=0\); simplify brackets to \(-2\omega\), \(-2\omega^2\); sum.$m042e$),
  ('academic', 'math', 1640, $m043c${"text":"\\(|z-z_1|+|z-z_2| = 2a\\) with \\(2a > |z_1-z_2|\\) is the locus of \\(z\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"complex_quad"}$m043c$::jsonb, $m043o$["**Ellipse** with foci \\(z_1,z_2\\).","A parabola","A hyperbola","A straight line"]$m043o$::jsonb, 0, $m043e$Sum of distances to two fixed points constant.$m043e$),
  ('academic', 'math', 1646, $m044c${"text":"Minimum of \\(|z-1|+|z-5|\\) over \\(z\\in\\mathbb{C}\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"complex_quad"}$m044c$::jsonb, $m044o$["\\(4\\)","\\(6\\)","\\(2\\)","\\(0\\)"]$m044o$::jsonb, 0, $m044e$Triangle inequality on segment from 1 to 5; minimum at points between.$m044e$),
  ('academic', 'math', 1652, $m045c${"text":"Real quadratic with **negative discriminant** \\(\\Delta<0\\) — nature of roots?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"complex_quad"}$m045c$::jsonb, $m045o$["Non-real complex conjugate pair.","Two distinct real roots","One repeated real root","No roots in \\(\\mathbb{C}\\)"]$m045o$::jsonb, 0, $m045e$\(\sqrt{\Delta}\) imaginary; coefficients real ⇒ conjugate pair.$m045e$),
  ('academic', 'math', 1659, $m046c${"text":"Roots of \\(x^2-px+q=0\\) differ by exactly 1. Relation between \\(p\\) and \\(q\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"complex_quad"}$m046c$::jsonb, $m046o$["\\(p^2 - 4q = 1\\)","\\(p^2 - 4q = 0\\)","\\(p = 4q\\)","\\(p+q=1\\)"]$m046o$::jsonb, 0, $m046e$\((\alpha-\beta)^2 = (\alpha+\beta)^2 - 4\alpha\beta\).$m046e$),
  ('academic', 'math', 1665, $m047c${"text":"Why must non-real roots of a real-coefficient polynomial occur in conjugate pairs?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"complex_quad"}$m047c$::jsonb, $m047o$["Complex conjugation preserves the polynomial (real coefficients) ⇒ roots closed under \\(\\bar{\\cdot}\\).","Because \\(|z|=1\\).","Only for cubics.","Roots must be rational."]$m047o$::jsonb, 0, $m047e$\(P(\bar z) = \overline{P(z)} = 0\) if \(P(z)=0\).$m047e$),
  ('academic', 'math', 1671, $m048c${"text":"Principal argument of \\(z = \\dfrac{-1-i\\sqrt{3}}{2}\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"complex_quad"}$m048c$::jsonb, $m048o$["\\(-2\\pi/3\\)","\\(\\pi/3\\)","\\(2\\pi/3\\)","\\(-\\pi/6\\)"]$m048o$::jsonb, 0, $m048e$Third quadrant; reference \(\pi/3\).$m048e$),
  ('academic', 'math', 1677, $m049c${"text":"Multiplying \\(z\\) by \\(i\\) in the Argand plane?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"complex_quad"}$m049c$::jsonb, $m049o$["**Counter-clockwise** rotation by \\(\\pi/2\\); \\(|z|\\) unchanged.","Reflection in real axis","Dilation by factor \\(i\\)","Rotation by \\(\\pi\\)"]$m049o$::jsonb, 0, $m049e$\(\arg(iz) = \arg z + \pi/2\).$m049e$),
  ('academic', 'math', 1683, $m050c${"text":"All real roots of \\(x^4 - 5x^2 + 4 = 0\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"complex_quad"}$m050c$::jsonb, $m050o$["\\(x = \\pm 1,\\ \\pm 2\\)","\\(x = 1,2\\) only","\\(x = \\pm \\sqrt{5}\\)","No real roots"]$m050o$::jsonb, 0, $m050e$Let \(u=x^2\); \((u-1)(u-4)=0\).$m050e$),
  ('academic', 'math', 1690, $m051c${"text":"**Singular** vs **non-singular** matrix — inverse?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"matrices_prob"}$m051c$::jsonb, $m051o$["Singular: \\(\\det A = 0\\), no inverse; non-singular: \\(\\det A \\neq 0\\), inverse exists.","Singular matrices always have two inverses.","Determinant is always 1 for invertible matrices.","Only diagonal matrices are invertible."]$m051o$::jsonb, 0, $m051e$\(A^{-1}\) needs \(\det A \neq 0\).$m051e$),
  ('academic', 'math', 1696, $m052c${"text":"\\(|A|=4\\) for a \\(3\\times 3\\) matrix \\(A\\). Find \\(|\\mathrm{adj}(A)|\\).","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"matrices_prob"}$m052c$::jsonb, $m052o$["\\(16\\)","\\(4\\)","\\(64\\)","\\(12\\)"]$m052o$::jsonb, 0, $m052e$\(|\mathrm{adj}A| = |A|^{n-1} = 4^2\).$m052e$),
  ('academic', 'math', 1702, $m053c${"text":"**Cayley–Hamilton** theorem says what about a square matrix \\(A\\)?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"matrices_prob"}$m053c$::jsonb, $m053o$["\\(A\\) satisfies its own characteristic polynomial: \\(p_A(A)=0\\).","\\(\\det A = 0\\) always","\\(A\\) is diagonalizable","\\(A^2 = I\\) always"]$m053o$::jsonb, 0, $m053e$Substitute matrix into characteristic equation.$m053e$),
  ('academic', 'math', 1708, $m054c${"text":"\\(P(A)=0.3\\), \\(P(B)=0.4\\), \\(P(A\\cup B)=0.58\\). Are \\(A,B\\) independent?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"matrices_prob"}$m054c$::jsonb, $m054o$["**Yes** — \\(P(A\\cap B) = 0.12 = P(A)P(B)\\).","No","Cannot tell","Only if mutually exclusive"]$m054o$::jsonb, 0, $m054e$\(P(A\cap B) = P(A)+P(B)-P(A\cup B)\).$m054e$),
  ('academic', 'math', 1714, $m055c${"text":"\\(AX=B\\) has **infinitely many** solutions when?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"matrices_prob"}$m055c$::jsonb, $m055o$["\\(|A|=0\\) and system consistent (e.g. \\((\\mathrm{adj}A)B=0\\) in \\(3\\times 3\\) case / rank conditions).","\\(|A|\\neq 0\\)","Always for square \\(A\\)","Never for linear systems"]$m055o$::jsonb, 0, $m055e$Singular + compatible ⇒ line/plane of solutions.$m055e$),
  ('academic', 'math', 1721, $m056c${"text":"\\(A\\) orthogonal \\((AA^T = I)\\). Possible values of \\(\\det A\\)?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"matrices_prob"}$m056c$::jsonb, $m056o$["\\(\\pm 1\\)","\\(0,1\\)","Any real number","\\(2\\) only"]$m056o$::jsonb, 0, $m056e$\(|AA^T|=|A|^2=1\).$m056e$),
  ('academic', 'math', 1727, $m057c${"text":"**Mutually exclusive** vs **independent** events?","pack":"puc_math_jee_neet_100","qtype":"conceptual","block":"matrices_prob"}$m057c$::jsonb, $m057o$["Mutually exclusive: cannot both occur (\\(P(A\\cap B)=0\\)); independent: \\(P(A\\cap B)=P(A)P(B)\\) (can co-occur).","They are synonyms.","Independent implies \\(P(A\\cap B)=0\\).","Mutually exclusive implies independence."]$m057o$::jsonb, 0, $m057e$Exclusive forbids overlap; independence is probabilistic factorization.$m057e$),
  ('academic', 'math', 1733, $m058c${"text":"Fair coin 10 times: probability of **exactly** 5 heads?","pack":"puc_math_jee_neet_100","qtype":"numerical","block":"matrices_prob"}$m058c$::jsonb, $m058o$["\\(63/256\\)","\\(1/2\\)","\\(105/512\\) (\\(\\binom{10}{4}/2^{10}\\))","\\(1/32\\)"]$m058o$::jsonb, 0, $m058e$\(\binom{10}{5}/2^{10} = 252/1024 = 63/256\).$m058e$),
